    0x73, 0x00, 0x00, 0x00, // ecall
    0x6f, 0x00, 0x00, 0x00, // jal zero, 0
];

const FDT_MAGIC: u32 = 0xd00d_feed;
const FDT_BEGIN_NODE: u32 = 1;
const FDT_END_NODE: u32 = 2;
const FDT_PROP: u32 = 3;
const FDT_NOP: u32 = 4;
const FDT_END: u32 = 9;

fn detect_fdt_memory_size(fdt: usize) -> Option<usize> {
    if fdt == 0 {
        return None;
    }
    let magic = fdt_read_be32(fdt)?;
    if magic != FDT_MAGIC {
        return None;
    }
    let off_dt_struct = fdt_read_be32(fdt + 8)? as usize;
    let off_dt_strings = fdt_read_be32(fdt + 12)? as usize;
    let size_dt_strings = fdt_read_be32(fdt + 32)? as usize;
    let size_dt_struct = fdt_read_be32(fdt + 36)? as usize;
    let struct_start = fdt.checked_add(off_dt_struct)?;
    let struct_end = struct_start.checked_add(size_dt_struct)?;
    let strings_start = fdt.checked_add(off_dt_strings)?;

    let mut cursor = struct_start;
    let mut depth = 0usize;
    let mut node_is_memory = [false; 16];
    let mut address_cells = 2usize;
    let mut size_cells = 1usize;

    while cursor + 4 <= struct_end {
        let token = fdt_read_be32(cursor)?;
        cursor += 4;
        match token {
            FDT_BEGIN_NODE => {
                let name_start = cursor;
                let name_len = fdt_cstr_len(name_start, struct_end)?;
                cursor = align4(name_start + name_len + 1);
                depth = depth.saturating_add(1);
                if depth < node_is_memory.len() {
                    node_is_memory[depth] = fdt_node_name_is_memory(name_start, name_len);
                }
            }
            FDT_END_NODE => {
                if depth < node_is_memory.len() {
                    node_is_memory[depth] = false;
                }
                depth = depth.saturating_sub(1);
            }
            FDT_PROP => {
                if cursor + 8 > struct_end {
                    return None;
                }
                let len = fdt_read_be32(cursor)? as usize;
                let nameoff = fdt_read_be32(cursor + 4)? as usize;
                cursor += 8;
                let value = cursor;
                let value_end = value.checked_add(len)?;
                if value_end > struct_end {
                    return None;
                }
                if depth == 1
                    && len == 4
                    && fdt_prop_name_eq(strings_start, size_dt_strings, nameoff, b"#address-cells")
                {
                    let cells = fdt_read_be32(value)? as usize;
                    if (1..=2).contains(&cells) {
                        address_cells = cells;
                    }
                } else if depth == 1
                    && len == 4
                    && fdt_prop_name_eq(strings_start, size_dt_strings, nameoff, b"#size-cells")
                {
                    let cells = fdt_read_be32(value)? as usize;
                    if (1..=2).contains(&cells) {
                        size_cells = cells;
                    }
                } else if depth < node_is_memory.len()
                    && node_is_memory[depth]
                    && fdt_prop_name_eq(strings_start, size_dt_strings, nameoff, b"reg")
                    && let Some(size) = fdt_memory_reg_size(value, len, address_cells, size_cells)
                {
                    return Some(size);
                }
                cursor = align4(value_end);
            }
            FDT_NOP => {}
            FDT_END => break,
            _ => return None,
        }
    }
    None
}

fn fdt_memory_reg_size(
    value: usize,
    len: usize,
    address_cells: usize,
    size_cells: usize,
) -> Option<usize> {
    let tuple_cells = address_cells.checked_add(size_cells)?;
    let tuple_bytes = tuple_cells.checked_mul(4)?;
    if tuple_bytes == 0 || len < tuple_bytes {
        return None;
    }
    let mut offset = 0usize;
    while offset + tuple_bytes <= len {
        let base = fdt_read_cells(value + offset, address_cells)?;
        let size = fdt_read_cells(value + offset + address_cells * 4, size_cells)?;
        let end = base.checked_add(size)?;
        if base <= RAM_BASE as u64 && end > RAM_BASE as u64 {
            let managed = (end - RAM_BASE as u64) as usize;
            return Some(core::cmp::min(managed, MAX_RAM_SIZE));
        }
        offset += tuple_bytes;
    }
    None
}

fn fdt_read_cells(addr: usize, cells: usize) -> Option<u64> {
    if cells == 0 || cells > 2 {
        return None;
    }
    let mut value = 0u64;
    let mut idx = 0usize;
    while idx < cells {
        value = (value << 32) | fdt_read_be32(addr + idx * 4)? as u64;
        idx += 1;
    }
    Some(value)
}

fn fdt_read_be32(addr: usize) -> Option<u32> {
    Some(u32::from_be(unsafe {
        core::ptr::read_unaligned(addr as *const u32)
    }))
}

fn fdt_cstr_len(start: usize, end: usize) -> Option<usize> {
    let mut cursor = start;
    while cursor < end {
        let byte = unsafe { core::ptr::read_volatile(cursor as *const u8) };
        if byte == 0 {
            return Some(cursor - start);
        }
        cursor += 1;
    }
    None
}

fn fdt_node_name_is_memory(start: usize, len: usize) -> bool {
    let prefix = b"memory";
    if len < prefix.len() {
        return false;
    }
    let mut idx = 0usize;
    while idx < prefix.len() {
        let byte = unsafe { core::ptr::read_volatile((start + idx) as *const u8) };
        if byte != prefix[idx] {
            return false;
        }
        idx += 1;
    }
    len == prefix.len()
        || unsafe { core::ptr::read_volatile((start + prefix.len()) as *const u8) } == b'@'
}

fn fdt_prop_name_eq(strings: usize, strings_size: usize, nameoff: usize, expected: &[u8]) -> bool {
    if nameoff >= strings_size {
        return false;
    }
    let start = strings + nameoff;
    let end = strings + strings_size;
    let mut idx = 0usize;
    while idx < expected.len() {
        if start + idx >= end {
            return false;
        }
        let byte = unsafe { core::ptr::read_volatile((start + idx) as *const u8) };
        if byte != expected[idx] {
            return false;
        }
        idx += 1;
    }
    start + idx < end && unsafe { core::ptr::read_volatile((start + idx) as *const u8) } == 0
}

fn align4(value: usize) -> usize {
    (value + 3) & !3
}

