#[unsafe(no_mangle)]
extern "C" fn trap_handler(
    scause: usize,
    sepc: usize,
    _arg0: usize,
    _arg1: usize,
    _arg2: usize,
    _syscall_no: usize,
    stval: usize,
) -> usize {
    // 更新当前进程 TrapFrame，使 syscall（如 fork）能读到正确的寄存器值。
    // trap frame 位于 kernel_sp - TrapFrame::SIZE，由 trap_entry 汇编填写。
    let (frame_base, syscall_no, syscall_args) = {
        let proc = current();
        let frame_base = proc.kernel_trap_frame_base();
        unsafe {
            TrapFrame::copy_from_stack(frame_base, &mut proc.trap_frame);
        }
        let tf = &proc.trap_frame;
        (
            frame_base,
            tf.regs[17],
            [
                tf.regs[10],
                tf.regs[11],
                tf.regs[12],
                tf.regs[13],
                tf.regs[14],
                tf.regs[15],
            ],
        )
    };
    crate::syscall::reap_current_thread_group_detached_zombies();

    if scause >> 63 == 1 {
        // 中断（timer）
        let now = crate::timer::read_time();
        let woke = wake_sleepers(now)
            | crate::syscall::deliver_due_posix_timers(now)
            | crate::syscall::deliver_due_legacy_itimers(now);
        crate::syscall::rearm_timer();
        crate::syscall::signal::prepare_user_signal_return(frame_base);
        if matches!(current().state, ProcessState::Stopped) {
            schedule();
        }
        if timer_should_preempt_current(woke) {
            current().state = ProcessState::Ready;
            schedule();
        }
        0 // 中断不设用户返回值
    } else {
        // 异常
        match scause {
            8 => {
                crate::syscall::reap_background_process_skeletons();
                let result = crate::syscall::dispatch_trap(frame_base, syscall_no, syscall_args);
                let should_reschedule = crate::task::scheduler::take_reschedule_request()
                    && crate::task::scheduler::has_other_ready();
                crate::syscall::clear_completed_direct_fd_wait();
                complete_ecall_return(frame_base, result);
                crate::syscall::signal::prepare_user_signal_return(frame_base);
                if matches!(current().state, ProcessState::Stopped) {
                    let frame_base = current().kernel_trap_frame_base();
                    unsafe {
                        TrapFrame::copy_from_stack(frame_base, &mut current().trap_frame);
                    }
                    schedule();
                }
                if should_reschedule {
                    let frame_base = current().kernel_trap_frame_base();
                    unsafe {
                        TrapFrame::copy_from_stack(frame_base, &mut current().trap_frame);
                    }
                    current().state = ProcessState::Ready;
                    current().clear_block_reason();
                    schedule();
                }
                0
            }
            12 | 13 | 15 => page_fault_handler(frame_base, scause, sepc, stval),
            _ => user_sync_exception_handler(frame_base, scause),
        }
    }
}

fn complete_ecall_return(frame_base: usize, result: usize) {
    unsafe {
        let tf = &mut *(frame_base as *mut TrapFrame);
        if tf.scause == 8 {
            tf.regs[10] = result;
            tf.sepc += 4;
            tf.scause = 0;
        }
    }
}

