use core::sync::atomic::{AtomicU32, Ordering};

use crate::mm::page_table::PhysAddr;

pub const RAM_BASE: usize = 0x8000_0000; // QEMU virt 物理内存起点
pub const DEFAULT_RAM_SIZE: usize = 128 * 1024 * 1024;
pub const MAX_RAM_SIZE: usize = 1024 * 1024 * 1024;
const FRAME_SHIFT: usize = 12;
const FRAME_SIZE: usize = 1 << FRAME_SHIFT;
const FRAME_COUNT: usize = MAX_RAM_SIZE / FRAME_SIZE;
const MAX_ORDER: usize = 18;
const ORDER_COUNT: usize = MAX_ORDER + 1;
const FREE_NONE: u32 = u32::MAX;
const FREE_ORDER_NONE: u32 = 0;

static mut NEXT_FRAME: usize = 0; // 在 rust_main 里根据 kernel_end 初始化
static mut MANAGED_RAM_SIZE: usize = DEFAULT_RAM_SIZE;
static mut FRAME_REFS: [AtomicU32; FRAME_COUNT] = unsafe { core::mem::zeroed() };
static mut FRAME_PINNED: [AtomicU32; FRAME_COUNT] = unsafe { core::mem::zeroed() };
static mut FREE_NEXT: [AtomicU32; FRAME_COUNT] = unsafe { core::mem::zeroed() };
static mut FREE_ORDER: [AtomicU32; FRAME_COUNT] = unsafe { core::mem::zeroed() };
static FREE_AREA_HEADS: [AtomicU32; ORDER_COUNT] =
    [const { AtomicU32::new(FREE_NONE) }; ORDER_COUNT];

#[track_caller]
fn frame_index(pa: PhysAddr) -> usize {
    if !is_managed(pa) || !is_page_aligned(pa) {
        crate::console::puts("\n[FRAME] bad pa=0x");
        crate::trap::print_hex(pa.0);
        crate::console::puts("\n");
        panic!("frame_index: physical address out of managed RAM");
    }
    (pa.0 - RAM_BASE) >> FRAME_SHIFT
}

fn is_managed(pa: PhysAddr) -> bool {
    pa.0 >= RAM_BASE && pa.0 < managed_ram_end()
}

fn is_page_aligned(pa: PhysAddr) -> bool {
    pa.0 & 0xfff == 0
}

pub fn is_managed_frame(pa: PhysAddr) -> bool {
    is_managed(pa) && is_page_aligned(pa)
}

pub fn is_pinned_frame(pa: PhysAddr) -> bool {
    is_managed_frame(pa) && is_pinned_idx(frame_index(pa))
}

#[track_caller]
pub fn inc_ref(pa: PhysAddr) {
    let idx = frame_index(pa);
    unsafe {
        FRAME_REFS[idx].fetch_add(1, Ordering::Relaxed);
    }
}

