pub fn free_zeroed_frame(pa: PhysAddr) {
    let idx = frame_index(pa);
    if is_pinned_idx(idx) {
        panic!("free_zeroed_frame: frame is pinned");
    }
    let refs = unsafe { FRAME_REFS[idx].load(Ordering::Relaxed) };
    if refs != 1 {
        panic!("free_zeroed_frame: frame is not exclusively owned");
    }
    unsafe {
