pub fn dec_ref(pa: PhysAddr) -> u32 {
    let idx = frame_index(pa);
    if is_pinned_idx(idx) {
        panic!("dec_ref: frame is pinned");
    }
    let prev = unsafe { FRAME_REFS[idx].fetch_sub(1, Ordering::Relaxed) };
    if prev == 0 {
        panic!("dec_ref: frame refcount underflow");
    }
    if prev == 1 {
