pub fn get_ref(pa: PhysAddr) -> u32 {
    let idx = frame_index(pa);
    unsafe { FRAME_REFS[idx].load(Ordering::Relaxed) }
}

pub fn pin_frames(pa: PhysAddr, pages: usize) {
    let mut page = 0usize;
    while page < pages {
        let idx = frame_index(PhysAddr(pa.0 + page * FRAME_SIZE));
        let refs = unsafe { FRAME_REFS[idx].load(Ordering::Relaxed) };
        if refs != 1 {
            panic!("pin_frames: frame is not exclusively owned");
        }
        unsafe {
            FRAME_PINNED[idx].store(1, Ordering::Relaxed);
        }
        page += 1;
    }
