pub fn unpin_frames(pa: PhysAddr, pages: usize) {
    let mut page = 0usize;
    while page < pages {
        let idx = frame_index(PhysAddr(pa.0 + page * FRAME_SIZE));
        let prev = unsafe { FRAME_PINNED[idx].swap(0, Ordering::Relaxed) };
        if prev == 0 {
            panic!("unpin_frames: frame is not pinned");
        }
        page += 1;
    }
}

