use core::ptr;

// ─── 地址类型 ───

#[derive(Clone, Copy, PartialEq)]
pub struct PhysAddr(pub usize);

#[derive(Clone, Copy)]
pub struct VirtAddr(pub usize);

// ─── 页表项 ───

#[derive(Clone, Copy)]
pub struct PTEntry(u64);

/// 页表项的标志位
#[derive(Clone, Copy)]
pub struct PTEFlags(u8);

// bit 在 u8 中的位置
const V_BIT: u8 = 0;
const R_BIT: u8 = 1;
const W_BIT: u8 = 2;
const X_BIT: u8 = 3;
const U_BIT: u8 = 4;

impl PTEntry {
    // ── PTE 位常量（64 位层面）──
    const BIT_V: u64 = 1 << 0; // Valid
    const BIT_R: u64 = 1 << 1; // Readable
    const BIT_W: u64 = 1 << 2; // Writable
    const BIT_X: u64 = 1 << 3; // Executable
    const BIT_U: u64 = 1 << 4; // User-accessible
    /// RISC-V Sv39 RSW bit reserved for supervisor software, used as COW tag.
    const BIT_COW: u64 = 1 << 8;

    // ── COW 操作 ──

    pub fn is_cow(&self) -> bool {
        self.0 & Self::BIT_COW != 0
    }

    pub fn set_cow(&mut self) {
        self.0 |= Self::BIT_COW;
    }

    pub fn clear_cow(&mut self) {
        self.0 &= !Self::BIT_COW;
    }

    // ── 权限查询 ──

    pub fn is_r(&self) -> bool {
        self.0 & Self::BIT_R != 0
    }
    pub fn is_w(&self) -> bool {
        self.0 & Self::BIT_W != 0
    }
    pub fn is_x(&self) -> bool {
        self.0 & Self::BIT_X != 0
    }
    pub fn is_u(&self) -> bool {
        self.0 & Self::BIT_U != 0
    }
    pub fn is_valid(&self) -> bool {
        self.0 & Self::BIT_V != 0
    }

    // ── 写权限修改（仅操作 bit 2，不动其他位含 COW bit 62）──

    /// 设置或清除写权限。w=true → 恢复可写，w=false → 清除可写（fork 时共享父页）
    pub fn set_w(&mut self, w: bool) {
        if w {
            self.0 |= Self::BIT_W;
        } else {
            self.0 &= !Self::BIT_W;
        }
    }

    /// 清除写权限（fork 时父页变 COW 共享用）
    pub fn clear_w(&mut self) {
        self.0 &= !Self::BIT_W;
    }

    // ── flags 桥接（PTEntry ↔ PTEFlags）──

    /// 读低 5 位标志（V/R/W/X/U），丢弃高位信息（COW）
    pub fn flags(&self) -> PTEFlags {
        PTEFlags((self.0 & 0x1F) as u8)
    }

    /// Replace low permission bits while preserving PPN and software metadata
    /// such as the COW bit. Callers must keep leaf/table invariants valid.
    pub fn set_leaf_flags(&mut self, flags: PTEFlags) {
        self.0 = (self.0 & !0x1F) | flags.into_u64();
    }

    // ── 构造器 ──

    /// 空项（V=0，无效）
    pub fn empty() -> Self {
        Self(0)
    }

    /// 指向下一级页表的条目
    fn new_table(paddr: PhysAddr) -> Self {
        let ppn = paddr.0 >> 12;
        Self((ppn << 10) as u64 | Self::BIT_V)
    }

    /// 指向最终物理页的条目（带读写等标志）
    pub fn new_leaf(paddr: PhysAddr, flags: PTEFlags) -> Self {
        let ppn = paddr.0 >> 12;
        Self((ppn << 10) as u64 | flags.into_u64())
    }

    /// 取物理页号 → 物理地址
    pub fn ppn_to_addr(&self) -> PhysAddr {
        PhysAddr((((self.0 >> 10) & 0xFFFF_FFFF_FFFF) as usize) << 12)
    }
}

impl PTEFlags {
    // ── 构造器 ──

    pub fn new(r: bool, w: bool, x: bool, u: bool) -> Self {
        let mut f = 1u8 << V_BIT; // V 总是 1
        if r {
            f |= 1 << R_BIT;
        }
        if w {
            f |= 1 << W_BIT;
        }
        if x {
            f |= 1 << X_BIT;
        }
        if u {
            f |= 1 << U_BIT;
        }
        Self(f)
    }

    // ── 权限查询 ──

    pub fn is_x(&self) -> bool {
        self.0 & (1 << X_BIT) != 0
    }
    pub fn is_u(&self) -> bool {
        self.0 & (1 << U_BIT) != 0
    }

    // ── 内部 ──

    fn into_u64(self) -> u64 {
        self.0 as u64
    }
}

