const REG_SP: usize = 2;
const REG_TP: usize = 4;
const REG_A0: usize = 10;
const SSTATUS_SPIE: usize = 1 << 5;
const SSTATUS_FS_INITIAL: usize = 1 << 13;

/// Full user register snapshot saved by `trap_entry`.
///
/// Stack layout is exactly:
/// - `regs[0..32]` at offsets 0..256
/// - `sstatus`, `sepc`, `scause`, `stval` at offsets 256..288
///
/// `regs[0]` is kept as zero for indexing clarity. `regs[2]` is the user sp.
#[derive(Clone, Copy)]
#[repr(C)]
pub struct TrapFrame {
    pub regs: [usize; 32],
    pub sstatus: usize,
    pub sepc: usize,
    pub scause: usize,
    pub stval: usize,
}

impl TrapFrame {
    pub const SIZE: usize = core::mem::size_of::<Self>();

    pub const fn new_user(entry: usize, user_sp: usize) -> Self {
        let mut regs = [0; 32];
        regs[REG_SP] = user_sp;
        Self {
            regs,
            // SPP=0 returns to U-mode. SPIE=1 enables S-mode interrupts after
            // sret. FS=Initial is a stage-1 compatibility choice for lp64d
            // user binaries; full FPU context switching is still separate work.
            sstatus: SSTATUS_SPIE | SSTATUS_FS_INITIAL,
            sepc: entry,
            scause: 8,
            stval: 0,
        }
    }

    pub fn set_a0(&mut self, value: usize) {
        self.regs[REG_A0] = value;
    }

    pub fn set_sp(&mut self, value: usize) {
        self.regs[REG_SP] = value;
    }

    pub fn set_tp(&mut self, value: usize) {
        self.regs[REG_TP] = value;
    }

    /// Copy the trap frame from a live kernel stack image into an existing
    /// process snapshot without materializing a second full frame on the stack.
    ///
    /// # Safety
    ///
    /// `frame_base` must point to a complete `TrapFrame` stack image written by
    /// `trap_entry` on a live kernel stack.
    pub unsafe fn copy_from_stack(frame_base: usize, out: &mut Self) {
        unsafe {
            Self::copy_words(frame_base as *const usize, out as *mut Self as *mut usize);
        }
    }

    /// Write this trap frame to `frame_base` before jumping to `trap_exit_restore`.
    ///
    /// # Safety
    ///
    /// `frame_base` must point to writable kernel-stack space of `TrapFrame::SIZE`
    /// bytes and must be 16-byte aligned for the restore path.
    pub unsafe fn write_to_stack(&self, frame_base: usize) {
        unsafe {
            Self::copy_words(
                self as *const Self as *const usize,
                frame_base as *mut usize,
            );
        }
    }

    unsafe fn copy_words(src: *const usize, dst: *mut usize) {
        let mut idx = 0usize;
        while idx < Self::SIZE / core::mem::size_of::<usize>() {
            unsafe {
                *dst.add(idx) = *src.add(idx);
            }
            idx += 1;
        }
    }
}

const _: () = {
    assert!(core::mem::offset_of!(TrapFrame, regs) == 0);
    assert!(core::mem::offset_of!(TrapFrame, sstatus) == 256);
    assert!(core::mem::offset_of!(TrapFrame, sepc) == 264);
    assert!(core::mem::offset_of!(TrapFrame, scause) == 272);
    assert!(core::mem::offset_of!(TrapFrame, stval) == 280);
    assert!(TrapFrame::SIZE == 288);
};

