// stage-1: keep enough slots for contest runners whose tests may leave short-lived
// children around until their parent exits. Full process-table reclamation still
// needs a stricter lifecycle review.
pub(crate) const MAX_PROCESSES: usize = 128;
const SCHED_FIFO_POLICY: usize = 1;
const SCHED_RR_POLICY: usize = 2;
const SCHED_IDLE_POLICY: usize = 5;

#[derive(Clone, Copy, PartialEq, Eq)]
pub(crate) enum ProcessSlotState {
    Empty,
    Reserved,
    Occupied,
}

pub(crate) struct ProcessSlot {
    state: ProcessSlotState,
    process: Process,
}

impl ProcessSlot {
    pub(crate) const EMPTY: Self = Self {
        state: ProcessSlotState::Empty,
        process: Process::STAGING,
    };

    pub(crate) fn as_ref(&self) -> Option<&Process> {
        if matches!(self.state, ProcessSlotState::Occupied) {
            Some(&self.process)
        } else {
            None
        }
    }

    pub(crate) fn as_mut(&mut self) -> Option<&mut Process> {
        if matches!(self.state, ProcessSlotState::Occupied) {
            Some(&mut self.process)
        } else {
            None
        }
    }

    pub(crate) fn is_available(&self) -> bool {
        matches!(self.state, ProcessSlotState::Empty)
            || matches!(self.state, ProcessSlotState::Occupied)
                && matches!(self.process.state, ProcessState::Gone)
                && self.process.skeleton_resources_released
    }

    pub(crate) fn reserve(&mut self) -> Option<&mut Process> {
        if !self.is_available() {
            return None;
        }
        self.state = ProcessSlotState::Reserved;
        self.process = Process::STAGING;
        Some(&mut self.process)
    }

    pub(crate) fn abort_reserved(&mut self) {
        if matches!(self.state, ProcessSlotState::Reserved) {
            self.process = Process::STAGING;
            self.state = ProcessSlotState::Empty;
        }
    }

    pub(crate) fn reserved_mut(&mut self) -> Option<&mut Process> {
        if matches!(self.state, ProcessSlotState::Reserved) {
            Some(&mut self.process)
        } else {
            None
        }
    }

    pub(crate) fn commit_reserved(&mut self) {
        debug_assert!(matches!(self.state, ProcessSlotState::Reserved));
        self.state = ProcessSlotState::Occupied;
    }

    pub(crate) fn set_occupied(&mut self, process: Process) {
        self.process = process;
        self.state = ProcessSlotState::Occupied;
    }
}

pub(crate) static mut PROCESS_LIST: [ProcessSlot; MAX_PROCESSES] =
    [const { ProcessSlot::EMPTY }; MAX_PROCESSES];

pub(crate) static mut CURRENT: usize = 0;
static mut NEXT_PID: usize = 1;
static mut NEXT_PROCESS_GENERATION: usize = 1;
const PID_HISTORY_BITS: usize = 4096;
const PID_HISTORY_WORDS: usize = PID_HISTORY_BITS / 64;
static mut ALLOCATED_PID_HISTORY: [u64; PID_HISTORY_WORDS] = [0; PID_HISTORY_WORDS];
static mut NEED_RESCHED: bool = false;
static mut YIELD_SKIP_INDEX: usize = MAX_PROCESSES;

// ── 简单 helper ──

fn process_slot_mut(idx: usize) -> Option<&'static mut ProcessSlot> {
    if idx >= MAX_PROCESSES {
        return None;
    }
    let ptr = unsafe { PROCESS_LIST.as_mut_ptr() };
    Some(unsafe { &mut *ptr.add(idx) })
}

// Process-table access boundary:
// Read-only scans may include the current process. Mutable callbacks own the
// table borrow boundary and must not reenter the process table. Slot reservation
// helpers own the Reserved -> Occupied/Empty state transition for fork/clone.
pub(crate) fn for_each_process(mut f: impl FnMut(usize, &Process)) {
    for_each_process_except(MAX_PROCESSES, &mut f);
}

pub(crate) fn for_each_process_except(skip_idx: usize, f: &mut impl FnMut(usize, &Process)) {
    let ptr = unsafe { PROCESS_LIST.as_ptr() };
    for idx in 0..MAX_PROCESSES {
        if idx == skip_idx {
            continue;
        }
        let slot = unsafe { &*ptr.add(idx) };
        if let Some(proc) = slot.as_ref() {
            f(idx, proc);
        }
    }
}

pub(crate) fn find_process_index(mut predicate: impl FnMut(&Process) -> bool) -> Option<usize> {
    let mut found = None;
    for_each_process(|idx, proc| {
        if found.is_none() && predicate(proc) {
            found = Some(idx);
        }
    });
    found
}

pub(crate) fn with_process<T>(idx: usize, f: impl FnOnce(&Process) -> T) -> Option<T> {
    if idx >= MAX_PROCESSES {
        return None;
    }
    let ptr = unsafe { PROCESS_LIST.as_ptr() };
    let slot = unsafe { &*ptr.add(idx) };
    slot.as_ref().map(f)
}

// Mutable process-table callbacks own the table borrow boundary for their whole
// callback. Do not call current() or another process-table scan from `f`.
pub(crate) fn with_process_mut<T>(idx: usize, f: impl FnOnce(&mut Process) -> T) -> Option<T> {
    let slot = process_slot_mut(idx)?;
    slot.as_mut().map(f)
}

// Mutable process-table callbacks own the table borrow boundary for their whole
// callback. Do not call current() or another process-table scan from `f`. Return
// false from `f` to stop scanning early.
pub(crate) fn for_each_process_mut(mut f: impl FnMut(usize, &mut Process) -> bool) {
    for_each_process_mut_except(MAX_PROCESSES, &mut f);
}

pub(crate) fn for_each_process_mut_except(
    skip_idx: usize,
    f: &mut impl FnMut(usize, &mut Process) -> bool,
) {
    let ptr = unsafe { PROCESS_LIST.as_mut_ptr() };
    for idx in 0..MAX_PROCESSES {
        if idx == skip_idx {
            continue;
        }
        let slot = unsafe { &mut *ptr.add(idx) };
        if let Some(proc) = slot.as_mut()
            && !f(idx, proc)
        {
            break;
        }
    }
}

pub(crate) struct ProcessSlotReservation {
    idx: usize,
    active: bool,
}

impl ProcessSlotReservation {
    pub(crate) fn child_mut(&mut self) -> Option<&mut Process> {
        if !self.active {
            return None;
        }
        process_slot_mut(self.idx)?.reserved_mut()
    }

    pub(crate) fn commit(mut self) {
        if let Some(slot) = process_slot_mut(self.idx) {
            slot.commit_reserved();
        }
        self.active = false;
    }
}

impl Drop for ProcessSlotReservation {
    fn drop(&mut self) {
        if self.active
            && let Some(slot) = process_slot_mut(self.idx)
        {
            slot.abort_reserved();
        }
    }
}

pub(crate) fn reserve_process_slot(idx: usize) -> Option<ProcessSlotReservation> {
    let slot = process_slot_mut(idx)?;
    slot.reserve()?;
    Some(ProcessSlotReservation { idx, active: true })
}

pub fn find_empty_slot() -> Option<usize> {
    for (i, slot) in unsafe { PROCESS_LIST.iter().enumerate() } {
        if slot.is_available() {
            return Some(i);
        }
    }
    None
}

pub fn alloc_pid() -> usize {
    unsafe {
        loop {
            let pid = NEXT_PID;
            NEXT_PID += 1;
            if mark_pid_allocated(pid) {
                return pid;
            }
        }
    }
}

