static mut INFO: Option<Ext4Info> = None;
static mut ROOT_INODE: Option<Ext4InodeInfo> = None;
static mut ROOT_DIR: Option<Ext4DirInfo> = None;

pub fn init() {
    let Ok(info) = probe_superblock() else {
        unsafe {
            INFO = None;
            ROOT_INODE = None;
            ROOT_DIR = None;
        }
        return;
    };
    let root_inode = probe_root_inode(info).ok();
    let root_dir = root_inode.and_then(|inode| probe_root_dir(info, inode).ok());
    unsafe {
        INFO = Some(info);
        ROOT_INODE = root_inode;
        ROOT_DIR = root_dir;
    }
}

pub fn info() -> Option<Ext4Info> {
    unsafe { INFO }
}

pub fn root_inode_info() -> Option<Ext4InodeInfo> {
    unsafe { ROOT_INODE }
}

pub fn root_dir_info() -> Option<Ext4DirInfo> {
    unsafe { ROOT_DIR }
}

pub fn is_smoke_volume() -> bool {
    info().is_some_and(Ext4Info::has_smoke_label)
}

pub fn smoke_check_optional() {
    let Some(info) = info() else {
        return;
    };
    if !info.is_stage1_supported() || !info.has_smoke_label() {
        return;
    }
    console::puts("E4\n");
    if root_inode_info().is_some_and(Ext4InodeInfo::is_stage1_root_dir) {
        console::puts("ER\n");
    }

