static mut QUEUE_MEM: QueueMem = QueueMem([0; QUEUE_MEM_SIZE]);
static mut REQ: BlkReqHeader = BlkReqHeader {
    typ: VIRTIO_BLK_T_IN,
    reserved: 0,
    sector: 0,
};
static mut DATA: [u8; SECTOR_SIZE] = [0; SECTOR_SIZE];
static mut STATUS: u8 = 0xff;
static mut DEVICE: Option<VirtioMmio> = None;

pub fn init() {
    unsafe {
        DEVICE = probe_and_init();
    }
}

pub fn smoke_check_optional() {
    if device().is_none() {
        return;
    }
    let mut sector = [0u8; SECTOR_SIZE];
    if read_sector(0, &mut sector).is_ok() && sector.starts_with(b"UNIT00-BLK-SMOKE") {
        console::puts("VB\n");
    }
}

pub fn read_sector(sector: u64, out: &mut [u8; SECTOR_SIZE]) -> Result<(), ()> {
    let previous_sie = disable_interrupts();
    let result = read_sector_inner(sector, out);
    restore_interrupts(previous_sie);
    result
}

fn read_sector_inner(sector: u64, out: &mut [u8; SECTOR_SIZE]) -> Result<(), ()> {
    let Some(mmio) = device() else {
        return Err(());
    };
    unsafe {
        write_volatile(&raw mut STATUS, 0xff);
        REQ.typ = VIRTIO_BLK_T_IN;
        REQ.reserved = 0;
        REQ.sector = sector;
        core::ptr::write_bytes((&raw mut DATA) as *mut u8, 0, SECTOR_SIZE);

        let desc = desc_table();
        let avail = avail_ring();
        let used = used_ring();

        write_volatile(
            desc.add(0),
            VirtqDesc {
                addr: (&raw const REQ) as u64,
                len: core::mem::size_of::<BlkReqHeader>() as u32,
                flags: VIRTQ_DESC_F_NEXT,
                next: 1,
            },
        );
        write_volatile(
            desc.add(1),
            VirtqDesc {
                addr: (&raw const DATA) as u64,
                len: SECTOR_SIZE as u32,
                flags: VIRTQ_DESC_F_WRITE | VIRTQ_DESC_F_NEXT,
                next: 2,
            },
        );
        write_volatile(
            desc.add(2),
            VirtqDesc {
                addr: (&raw const STATUS) as u64,
                len: core::mem::size_of::<u8>() as u32,
                flags: VIRTQ_DESC_F_WRITE,
                next: 0,
            },
        );

        let start_idx = read_volatile(&raw const (*used).idx);
        let avail_idx = read_volatile(&raw const (*avail).idx);
        let avail_slot = (avail_idx as usize) % QUEUE_SIZE;
        write_volatile((&raw mut (*avail).ring[avail_slot]), 0);
        fence_io();
        write_volatile(&raw mut (*avail).idx, avail_idx.wrapping_add(1));
        fence_io();
        mmio.write(MMIO_QUEUE_NOTIFY, 0);

        let mut spins = 0usize;
        while read_volatile(&raw const (*used).idx) == start_idx {
            spins += 1;
            if spins > 10_000_000 {
                return Err(());
            }
            core::hint::spin_loop();
        }
        fence_io();
        if read_volatile(&raw const STATUS) != VIRTIO_BLK_S_OK {
            return Err(());
        }
        core::ptr::copy_nonoverlapping(
            (&raw const DATA) as *const u8,
            out.as_mut_ptr(),
            SECTOR_SIZE,
        );
    }
    Ok(())
}

fn disable_interrupts() -> usize {
    let previous: usize;
    unsafe {
        asm!("csrrc {}, sstatus, {}", out(reg) previous, in(reg) SSTATUS_SIE);
    }
    previous & SSTATUS_SIE
}

fn restore_interrupts(previous_sie: usize) {
    if previous_sie != 0 {
        unsafe {
            asm!("csrs sstatus, {}", in(reg) SSTATUS_SIE);
        }
    }
}

