//! Stage-1 virtio-mmio net probe for QEMU virt.
//!
//! This only discovers the virtio-net device and its optional MAC address. It
//! does not initialize queues, receive packets, transmit packets, or change the
//! AF_INET socket data path.

use core::ptr::read_volatile;

use crate::{console, ext4, virtio_blk};

const MMIO_MAGIC: usize = 0x000;
const MMIO_VERSION: usize = 0x004;
const MMIO_DEVICE_ID: usize = 0x008;
const MMIO_DEVICE_FEATURES: usize = 0x010;
const MMIO_DEVICE_FEATURES_SEL: usize = 0x014;
const MMIO_CONFIG: usize = 0x100;

const VIRTIO_MAGIC: u32 = 0x7472_6976;
const VIRTIO_VERSION_LEGACY: u32 = 1;
const VIRTIO_VERSION_MODERN: u32 = 2;
const VIRTIO_DEVICE_NET: u32 = 1;
const VIRTIO_NET_F_MAC: u32 = 5;
const ETHER_ADDR_LEN: usize = 6;

#[derive(Clone, Copy)]
pub struct VirtioNetInfo {
    mac: [u8; ETHER_ADDR_LEN],
    has_mac: bool,
}

#[derive(Clone, Copy)]
struct VirtioMmio {
    base: usize,
}

static mut DEVICE: Option<VirtioNetInfo> = None;

pub fn init() {
    unsafe {
        DEVICE = probe();
    }
}

pub fn smoke_check_optional() {
    if ext4::is_smoke_volume()
        && let Some(info) = info()
    {
        let _ = info.mac();
        console::puts("VN\n");
    }
}

pub fn info() -> Option<VirtioNetInfo> {
    unsafe { DEVICE }
}

impl VirtioNetInfo {
    pub fn mac(self) -> Option<[u8; ETHER_ADDR_LEN]> {
        if self.has_mac { Some(self.mac) } else { None }
    }
}

fn probe() -> Option<VirtioNetInfo> {
    let mut idx = 0;
    while idx < virtio_blk::VIRTIO_MMIO_COUNT {
        let base = virtio_blk::VIRTIO_MMIO_START + idx * virtio_blk::VIRTIO_MMIO_STRIDE;
        let mmio = VirtioMmio { base };
        let version = mmio.read(MMIO_VERSION);
        if mmio.read(MMIO_MAGIC) == VIRTIO_MAGIC
            && (version == VIRTIO_VERSION_LEGACY || version == VIRTIO_VERSION_MODERN)
            && mmio.read(MMIO_DEVICE_ID) == VIRTIO_DEVICE_NET
        {
            return Some(read_info(mmio));
        }
        idx += 1;
    }
    None
}

fn read_info(mmio: VirtioMmio) -> VirtioNetInfo {
    mmio.write(MMIO_DEVICE_FEATURES_SEL, 0);
    let features = mmio.read(MMIO_DEVICE_FEATURES);
    let has_mac = features & (1 << VIRTIO_NET_F_MAC) != 0;
    let mut mac = [0u8; ETHER_ADDR_LEN];
    if has_mac {
        for (idx, byte) in mac.iter_mut().enumerate() {
            *byte = mmio.read_u8(MMIO_CONFIG + idx);
        }
    }
    VirtioNetInfo { mac, has_mac }
}

impl VirtioMmio {
    fn read(self, offset: usize) -> u32 {
        unsafe { read_volatile((self.base + offset) as *const u32) }
    }

    fn read_u8(self, offset: usize) -> u8 {
        unsafe { read_volatile((self.base + offset) as *const u8) }
    }

    fn write(self, offset: usize, value: u32) {
        unsafe {
            core::ptr::write_volatile((self.base + offset) as *mut u32, value);
        }
    }
}

