#[derive(Clone, Copy)]
pub struct ExecString {
    bytes: [u8; MAX_EXEC_STR_LEN],
    len: usize,
}

impl ExecString {
    pub const EMPTY: Self = Self {
        bytes: [0; MAX_EXEC_STR_LEN],
        len: 0,
    };

    pub fn from_array(bytes: [u8; MAX_EXEC_STR_LEN], len: usize) -> Option<Self> {
        if len > MAX_EXEC_STR_LEN {
            return None;
        }
        Some(Self { bytes, len })
    }

    pub fn from_slice(bytes: &[u8]) -> Option<Self> {
        if bytes.len() > MAX_EXEC_STR_LEN {
            return None;
        }
        let mut out = [0u8; MAX_EXEC_STR_LEN];
        out[..bytes.len()].copy_from_slice(bytes);
        Some(Self {
            bytes: out,
            len: bytes.len(),
        })
    }

    fn as_bytes(&self) -> &[u8] {
        &self.bytes[..self.len]
    }
}

pub struct ExecArgs {
    argv: [ExecString; MAX_EXEC_ARGS],
    argc: usize,
    envp: [ExecString; MAX_EXEC_ENVS],
    envc: usize,
}

#[derive(Clone, Copy)]
struct InterpreterPath {
    bytes: [u8; MAX_EXEC_STR_LEN],
    len: usize,
}

impl InterpreterPath {
    fn from_slice(path: &[u8]) -> Option<Self> {
        if path.is_empty() || path.len() > MAX_EXEC_STR_LEN {
            return None;
        }
        let mut bytes = [0u8; MAX_EXEC_STR_LEN];
        bytes[..path.len()].copy_from_slice(path);
        Some(Self {
            bytes,
            len: path.len(),
        })
    }

    fn as_bytes(&self) -> &[u8] {
        &self.bytes[..self.len]
    }
}

#[derive(Clone, Copy)]
struct ScriptInterpreter {
    path: InterpreterPath,
    arg: Option<ExecString>,
}

impl ExecArgs {
    pub const fn new() -> Self {
        Self {
            argv: [ExecString::EMPTY; MAX_EXEC_ARGS],
            argc: 0,
            envp: [ExecString::EMPTY; MAX_EXEC_ENVS],
            envc: 0,
        }
    }

    pub fn push_arg(&mut self, arg: ExecString) -> bool {
        if self.argc == MAX_EXEC_ARGS {
            return false;
        }
        self.argv[self.argc] = arg;
        self.argc += 1;
        true
    }

    pub fn push_env(&mut self, env: ExecString) -> bool {
        if self.envc == MAX_EXEC_ENVS {
            return false;
        }
        self.envp[self.envc] = env;
        self.envc += 1;
        true
    }

    fn argv(&self) -> &[ExecString] {
        &self.argv[..self.argc]
    }

    fn envp(&self) -> &[ExecString] {
        &self.envp[..self.envc]
    }

    fn for_script(
        interpreter: &[u8],
        interpreter_arg: Option<ExecString>,
        script_path: &[u8],
        original: &ExecArgs,
    ) -> Option<Self> {
        let mut args = Self::new();
        if !args.push_arg(ExecString::from_slice(interpreter)?) {
            return None;
        }
        if let Some(arg) = interpreter_arg
            && !args.push_arg(arg)
        {
            return None;
        }

