pub(super) fn sys_exit(code: usize) -> ! {
    finish_current_process(code)
}

pub(super) fn sys_exit_group(code: usize) -> ! {
    finish_current_thread_group(code)
}

pub(super) fn finish_current_thread_group(wait_code: usize) -> ! {
    let tgid = current().thread_group_id;
    record_thread_group_exit_status(tgid, wait_code);
    finish_thread_group_members_except_current(tgid, wait_code);
    finish_current_process(wait_code)
}

pub(super) fn finish_current_process(wait_code: usize) -> ! {
    let (pid, current_pidfd) = {
        let cur = current();
        (cur.pid, pidfd::PidFd::new(cur.pid, cur.pid_generation))
    };
    signal::notify_parent_death(pid);
    reparent_orphans_to_init();
    let tgid = finish_live_process_for_exit_idx(
        crate::task::scheduler::current_index(),
        current(),
        wait_code,
    );
    unsafe {
        asm!("sfence.vma");
    }
    wake_vfork_parent(pid);
    notify_thread_group_exit_if_ready(tgid);
    wake_pidfd_readers(current_pidfd);
    schedule()
}

pub(super) fn terminate_thread_group(tgid: usize, wait_code: usize) {
    record_thread_group_exit_status(tgid, wait_code);
    let current_is_member = finish_thread_group_members_except_current(tgid, wait_code);
    if current_is_member {
        finish_current_process(wait_code);
    }
}

pub(super) fn terminate_process_index(idx: usize, wait_code: usize) {
    let Some(tgid) = with_process(idx, |target| {
        if matches!(target.state, ProcessState::Gone | ProcessState::Zombie(_)) {
            None
        } else {
            Some(target.thread_group_id)
        }
    })
    .flatten() else {
        return;
    };
    terminate_thread_group(tgid, wait_code);
}

pub(super) fn stop_thread_group(tgid: usize, sig: usize) -> bool {
    let current_pid = current().pid;
    let mut current_stopped = false;
    let mut transitioned_any = false;
    thread_group::for_each_member_mut(tgid, |_, target| {
        if matches!(target.state, ProcessState::Zombie(_)) {
            return true;
        }
        let transitioned = stop_process_for_signal(target, sig);
        transitioned_any |= transitioned;
        if transitioned && target.pid == current_pid {
            current_stopped = true;
        }
        true
    });
    if transitioned_any {
        notify_thread_group_job_event(tgid, CLD_STOPPED, sig as u32);
    }
    current_stopped
}

pub(super) fn continue_thread_group(tgid: usize) {
    let mut continued_any = false;
    thread_group::for_each_member_mut(tgid, |_, target| {
        if !matches!(target.state, ProcessState::Stopped) {
            return true;
        }
        target.jobctl_stop_signal = 0;
        target.jobctl_stop_reported = true;
        target.jobctl_continued_pending = true;
        target.state = ProcessState::Ready;
        continued_any = true;
        true
    });
    if continued_any {
        notify_thread_group_job_event(tgid, CLD_CONTINUED, SIGCONT as u32);
        crate::task::scheduler::request_reschedule();
    }
}

fn stop_process_for_signal(target: &mut Process, sig: usize) -> bool {
    if matches!(target.state, ProcessState::Stopped) {
        return false;
    }
    if matches!(target.state, ProcessState::Blocked) {
        signal::interrupt_blocked_syscall_for_stop(target);
    }
    target.jobctl_stop_signal = sig;
    target.jobctl_stop_reported = false;
    target.jobctl_continued_pending = false;
    target.state = ProcessState::Stopped;
    true
}

fn notify_thread_group_job_event(tgid: usize, code: u32, status: u32) {
    let mut event = None;
    thread_group::for_each_member_mut(tgid, |_, proc| {
        if proc.is_waitable_representative() {
            record_representative_job_event(proc, code, status);
            event = Some(child_lifecycle_event(proc));
            return false;
        }
        true
    });
    if let Some(event) = event {
        signal::notify_child_job_event(event, code, status);
    }
}

fn record_representative_job_event(proc: &mut Process, code: u32, status: u32) {
    match code {
        CLD_STOPPED => {
            proc.jobctl_stop_signal = status as usize;
            proc.jobctl_stop_reported = false;
            proc.jobctl_continued_pending = false;
        }
        CLD_CONTINUED => {
            proc.jobctl_stop_signal = 0;
            proc.jobctl_stop_reported = true;
            proc.jobctl_continued_pending = true;
        }
        _ => {}
    }
}

pub(crate) fn prepare_current_thread_group_for_exec() {
    let (old_tid, old_tid_generation, tgid) = {
        let cur = current();
        (cur.pid, cur.pid_generation, cur.thread_group_id)
    };
    let tgid_pid_generation = pidfd_for_open_target(tgid)
        .map(|pidfd| pidfd.generation())
        .unwrap_or(old_tid_generation);
    let exec_exit_signal = exec_exit_signal_for_thread_group(tgid, current().exit_signal);
    // During non-leader exec the old tid remains the temporary exact parent
    // until sibling parent-death notifications finish. The externally live
    // process identity is still the tgid, so pidfd readers for tgid must not
    // be woken while the survivor is being installed.
    let exact_parent_survivor = if old_tid == tgid { tgid } else { old_tid };
    detach_thread_group_members_for_exec(tgid, old_tid, exact_parent_survivor, tgid);
    if old_tid != tgid {
        retarget_children_parent_pid_for_exec(old_tid, tgid);
        let cur = current();
        cur.pid = tgid;
        cur.pid_generation = tgid_pid_generation;
        wake_pidfd_readers(pidfd::PidFd::new(old_tid, old_tid_generation));
    }
    current().exit_signal = exec_exit_signal;
}

fn exec_exit_signal_for_thread_group(tgid: usize, fallback: usize) -> usize {
    thread_group::waitable_representative_index(tgid)
        .and_then(|idx| with_process(idx, |proc| proc.exit_signal))
        .unwrap_or(fallback)
}

pub(super) fn smoke_check_exec_preserves_clone_exit_signal_owner() -> bool {
    const LEADER_IDX: usize = MAX_PROCESSES - 2;
    const THREAD_IDX: usize = MAX_PROCESSES - 1;
    const TGID: usize = 41;
    const THREAD_PID: usize = 42;
    const SMOKE_CLONE_SIGNAL: usize = 10; // SIGUSR1

    if with_process(LEADER_IDX, |_| ()).is_some() || with_process(THREAD_IDX, |_| ()).is_some() {
        return false;
    }

    let mut leader = Process::STAGING;
    leader.pid = TGID;
    leader.thread_group_id = TGID;
    leader.exit_signal = SMOKE_CLONE_SIGNAL;
    leader.state = ProcessState::Ready;

