pub(super) fn sys_futex(
    uaddr: *const u8,
    op: usize,
    val: usize,
    timeout_or_val2: *const u8,
    uaddr2: *const u8,
    val3: usize,
) -> usize {
    let op = match FutexOp::decode(op) {
        Ok(op) => op,
        Err(errno) => return errno,
    };
    match op.cmd {
        FUTEX_WAKE | FUTEX_WAKE_BITSET => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            if let Err(errno) = validate_futex_uaddr(uaddr as usize, false) {
                return errno;
            }
            let bitset = futex_wake_bitset(op.cmd, val3);
            if bitset == 0 {
                return linux_error(EINVAL);
            }
            wake_futex_waiters(futex_key(uaddr as usize, op.private), val, bitset)
        }
        FUTEX_WAIT | FUTEX_WAIT_BITSET => {
            let bitset = futex_wait_bitset(op.cmd, val3);
            if bitset == 0 {
                return linux_error(EINVAL);
            }
            let actual = match read_futex_word(uaddr as usize, false) {
                Ok(actual) => actual,
                Err(errno) => return errno,
            };
            if actual != val as u32 {
                return linux_error(EAGAIN);
            }
            let deadline = match futex_wait_deadline(op.cmd, timeout_or_val2) {
                Ok(deadline) => deadline,
                Err(errno) => return errno,
            };
            block_on_futex(futex_key(uaddr as usize, op.private), deadline, bitset);
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            let max_wake = match futex_requeue_count_arg(val) {
                Ok(count) => count,
                Err(errno) => return errno,
            };
            let max_requeue = match futex_requeue_count_arg(timeout_or_val2 as usize) {
                Ok(count) => count,
                Err(errno) => return errno,
            };
            let compare = if op.cmd == FUTEX_CMP_REQUEUE {
                Some(val3 as u32)
            } else {
                None
            };
            futex_requeue(op, uaddr, uaddr2, max_wake, max_requeue, compare)
        }
        FUTEX_WAKE_OP => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            let max_wake = futex_wake_op_count_arg(val);
            let max_wake2 = futex_wake_op_count_arg(timeout_or_val2 as usize);
            futex_wake_op(op, uaddr, uaddr2, max_wake, max_wake2, val3 as u32)
        }
        FUTEX_LOCK_PI => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            futex_lock_pi(uaddr, timeout_or_val2, op.private)
        }
        FUTEX_LOCK_PI2 => futex_lock_pi(uaddr, timeout_or_val2, op.private),
        FUTEX_TRYLOCK_PI => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            futex_trylock_pi(uaddr)
        }
        FUTEX_UNLOCK_PI => {
            if op.realtime {
                return linux_error(EINVAL);
            }
            futex_unlock_pi(uaddr, op.private)
        }
        FUTEX_WAIT_REQUEUE_PI => futex_wait_requeue_pi(op, uaddr, val, timeout_or_val2, uaddr2),
        FUTEX_CMP_REQUEUE_PI => {
            let max_requeue = match futex_requeue_count_arg(timeout_or_val2 as usize) {
                Ok(count) => count,
                Err(errno) => return errno,
            };
            futex_cmp_requeue_pi(op, uaddr, uaddr2, val, max_requeue, val3 as u32)
        }

