#[derive(Clone, Copy)]
struct UnixAcceptQueue {
    endpoints: [Option<usize>; MAX_UNIX_ACCEPT_QUEUE],
    head: usize,
    count: usize,
}

impl UnixAcceptQueue {
    const EMPTY: Self = Self {
        endpoints: [None; MAX_UNIX_ACCEPT_QUEUE],
        head: 0,
        count: 0,
    };

    fn is_empty(self) -> bool {
        self.count == 0
    }

    fn is_full(self) -> bool {
        self.count == self.endpoints.len()
    }

    fn push(&mut self, endpoint: usize) -> bool {
        if self.is_full() {
            return false;
        }
        let idx = (self.head + self.count) % self.endpoints.len();
        self.endpoints[idx] = Some(endpoint);
        self.count += 1;
        true
    }

    fn pop(&mut self) -> Option<usize> {
        if self.count == 0 {
            return None;
        }
        let endpoint = self.endpoints[self.head];
        self.endpoints[self.head] = None;
        self.head = (self.head + 1) % self.endpoints.len();
        self.count -= 1;
        if self.count == 0 {
            self.head = 0;
        }

