pub const MAX_EPOLL_WATCHES: usize = 32;

const MAX_EPOLL_INSTANCES: usize = 16;

#[derive(Clone, Copy, PartialEq, Eq)]
pub struct Epoll(usize);

#[derive(Clone, Copy)]
pub struct EpollEvent {
    pub events: u32,
    pub data: u64,
}

#[derive(Clone, Copy)]
pub struct EpollWatch {
    pub fd: usize,
    pub open_file: usize,
    pub event: EpollEvent,
}

#[derive(Clone, Copy)]
struct EpollWatchSlot {
    fd: usize,
    open_file: usize,
    event: EpollEvent,
    used: bool,
}

impl EpollWatchSlot {
    const EMPTY: Self = Self {
        fd: 0,
        open_file: 0,
        event: EpollEvent { events: 0, data: 0 },
        used: false,
    };
}

#[derive(Clone, Copy)]
struct EpollSlot {
    watches: [EpollWatchSlot; MAX_EPOLL_WATCHES],
    used: bool,
}

impl EpollSlot {
    const EMPTY: Self = Self {
        watches: [EpollWatchSlot::EMPTY; MAX_EPOLL_WATCHES],
        used: false,
    };
}

#[derive(Clone, Copy)]
pub enum EpollError {
    BadEpoll,
    BadFd,
    Exists,
    NotFound,
    NoSpace,
}

static mut EPOLLS: [EpollSlot; MAX_EPOLL_INSTANCES] = [EpollSlot::EMPTY; MAX_EPOLL_INSTANCES];

pub fn alloc() -> Option<Epoll> {
    let ptr = unsafe { EPOLLS.as_mut_ptr() };
    for idx in 0..MAX_EPOLL_INSTANCES {
        let slot = unsafe { &mut *ptr.add(idx) };
        if !slot.used {
            *slot = EpollSlot {
                watches: [EpollWatchSlot::EMPTY; MAX_EPOLL_WATCHES],
                used: true,
            };
            return Some(Epoll(idx));
        }
    }
    None
}

pub fn close(epoll: Epoll) {
    if let Some(slot) = slot_mut(epoll) {
        release_watches(slot);
        *slot = EpollSlot::EMPTY;
    }
}

pub fn add(epoll: Epoll, fd: usize, open_file: usize, event: EpollEvent) -> Result<(), EpollError> {
    let slot = slot_mut(epoll).ok_or(EpollError::BadEpoll)?;
    if find_watch(slot, fd, open_file).is_some() {
        return Err(EpollError::Exists);
    }
    for watch in slot.watches.iter_mut() {
        if !watch.used {
            if !retain_open_file_ref(open_file) {
                return Err(EpollError::BadFd);
            }
            *watch = EpollWatchSlot {
                fd,
                open_file,
                event,
                used: true,
            };
            return Ok(());
        }
    }
    Err(EpollError::NoSpace)
}

pub fn modify(
    epoll: Epoll,
    fd: usize,
    open_file: usize,
    event: EpollEvent,
) -> Result<(), EpollError> {
    let slot = slot_mut(epoll).ok_or(EpollError::BadEpoll)?;
    let watch = find_watch_mut(slot, fd, open_file).ok_or(EpollError::NotFound)?;
    watch.event = event;
    Ok(())
}

pub fn delete(epoll: Epoll, fd: usize, open_file: usize) -> Result<(), EpollError> {
    let slot = slot_mut(epoll).ok_or(EpollError::BadEpoll)?;
    let watch = find_watch_mut(slot, fd, open_file).ok_or(EpollError::NotFound)?;
    release_open_file_ref(watch.open_file);
    *watch = EpollWatchSlot::EMPTY;
    Ok(())
}

pub fn remove_watches_for_open_file(open_file: usize) {
    let ptr = unsafe { EPOLLS.as_mut_ptr() };
    for idx in 0..MAX_EPOLL_INSTANCES {
        let slot = unsafe { &mut *ptr.add(idx) };
        if !slot.used {
            continue;
        }
        for watch in slot.watches.iter_mut() {
            if watch.used && watch.open_file == open_file {
                release_open_file_ref(watch.open_file);
                *watch = EpollWatchSlot::EMPTY;
            }
        }
    }
}

pub fn watch_at(epoll: Epoll, idx: usize) -> Result<Option<EpollWatch>, EpollError> {
    if idx >= MAX_EPOLL_WATCHES {
        return Ok(None);
    }
    let slot = slot(epoll).ok_or(EpollError::BadEpoll)?;
    let watch = slot.watches[idx];
    if !watch.used {
        return Ok(None);
    }
    Ok(Some(EpollWatch {
        fd: watch.fd,
        open_file: watch.open_file,
        event: watch.event,
    }))
}

pub fn ino(epoll: Epoll) -> u64 {
    4000 + epoll.0 as u64
}

fn find_watch(slot: &EpollSlot, fd: usize, open_file: usize) -> Option<EpollWatchSlot> {
    slot.watches
        .iter()
        .copied()
        .find(|watch| watch_matches(*watch, fd, open_file))
}

fn find_watch_mut(
    slot: &mut EpollSlot,
    fd: usize,
    open_file: usize,
) -> Option<&mut EpollWatchSlot> {
    slot.watches
        .iter_mut()
        .find(|watch| watch_matches(**watch, fd, open_file))
}

fn watch_matches(watch: EpollWatchSlot, fd: usize, open_file: usize) -> bool {
    watch.used && watch.fd == fd && watch.open_file == open_file
}

fn release_watches(slot: &mut EpollSlot) {
    for watch in slot.watches.iter_mut() {
        if watch.used {
            release_open_file_ref(watch.open_file);
            *watch = EpollWatchSlot::EMPTY;
        }
    }
}

fn slot(epoll: Epoll) -> Option<EpollSlot> {
    if epoll.0 >= MAX_EPOLL_INSTANCES {
        return None;
    }
    let slot = unsafe { EPOLLS[epoll.0] };
    slot.used.then_some(slot)
}

fn slot_mut(epoll: Epoll) -> Option<&'static mut EpollSlot> {
    if epoll.0 >= MAX_EPOLL_INSTANCES {
        return None;
    }
    let slot = unsafe { &mut EPOLLS[epoll.0] };
    slot.used.then_some(slot)
}

