const EVENTFD_COUNTER_MAX: u64 = u64::MAX - 1;

#[derive(Clone, Copy, PartialEq, Eq)]
pub struct EventFd(usize);

#[derive(Clone, Copy)]
struct EventFdSlot {
    counter: u64,
    semaphore: bool,
    used: bool,
}

impl EventFdSlot {
    const EMPTY: Self = Self {
        counter: 0,
        semaphore: false,
        used: false,
    };
}

#[derive(Clone, Copy)]
pub struct EventFdState {
    pub counter: u64,
}

#[derive(Clone, Copy)]
pub enum EventFdError {
    BadEventFd,
    Empty,
    Full,
    Invalid,
}

static mut EVENTFDS: [EventFdSlot; MAX_EVENTFDS] = [EventFdSlot::EMPTY; MAX_EVENTFDS];

pub fn alloc(initval: u64, semaphore: bool) -> Option<EventFd> {
    let ptr = unsafe { EVENTFDS.as_mut_ptr() };
    for idx in 0..MAX_EVENTFDS {
        let slot = unsafe { &mut *ptr.add(idx) };
        if !slot.used {
            *slot = EventFdSlot {
                counter: initval,
                semaphore,
                used: true,
            };
            return Some(EventFd(idx));
        }
    }
    None
}

pub fn close(eventfd: EventFd) {
    if let Some(slot) = slot_mut(eventfd) {
        *slot = EventFdSlot::EMPTY;
    }
}

pub fn read(eventfd: EventFd) -> Result<u64, EventFdError> {
    let slot = slot_mut(eventfd).ok_or(EventFdError::BadEventFd)?;
    if slot.counter == 0 {
        return Err(EventFdError::Empty);
    }
    if slot.semaphore {
        slot.counter -= 1;
        scheduler::wake_eventfd_writers(eventfd);
        Ok(1)
    } else {
        let value = slot.counter;
        slot.counter = 0;
        scheduler::wake_eventfd_writers(eventfd);
        Ok(value)
    }
}

pub fn write(eventfd: EventFd, value: u64) -> Result<(), EventFdError> {
    if value == u64::MAX {
        return Err(EventFdError::Invalid);
    }
    let slot = slot_mut(eventfd).ok_or(EventFdError::BadEventFd)?;
    if value > EVENTFD_COUNTER_MAX.saturating_sub(slot.counter) {
        return Err(EventFdError::Full);
    }
    slot.counter += value;
    if value != 0 {
        scheduler::wake_eventfd_readers(eventfd);
    }
    Ok(())
}

pub fn state(eventfd: EventFd) -> Option<EventFdState> {
    let slot = slot(eventfd)?;
    Some(EventFdState {
        counter: slot.counter,
    })
}

pub fn can_write(eventfd: EventFd) -> bool {
    state(eventfd)
        .map(|state| state.counter < EVENTFD_COUNTER_MAX)
        .unwrap_or(false)
}

pub fn ino(eventfd: EventFd) -> u64 {
    3000 + eventfd.0 as u64
}

fn slot(eventfd: EventFd) -> Option<EventFdSlot> {
    if eventfd.0 >= MAX_EVENTFDS {
        return None;
    }
    let slot = unsafe { EVENTFDS[eventfd.0] };
    slot.used.then_some(slot)
}

fn slot_mut(eventfd: EventFd) -> Option<&'static mut EventFdSlot> {
    if eventfd.0 >= MAX_EVENTFDS {
        return None;
    }
    let slot = unsafe { &mut EVENTFDS[eventfd.0] };
    slot.used.then_some(slot)
}
