const MAX_TIMERFDS: usize = 32;

#[derive(Clone, Copy, PartialEq, Eq)]
pub struct TimerFd(usize);

#[derive(Clone, Copy)]
struct TimerFdSlot {
    next_deadline: usize,
    interval_ticks: usize,
    pending: u64,
    active: bool,
    used: bool,
}

impl TimerFdSlot {
    const EMPTY: Self = Self {
        next_deadline: 0,
        interval_ticks: 0,
        pending: 0,
        active: false,
        used: false,
    };
}

#[derive(Clone, Copy)]
pub struct TimerFdState {
    pub remaining_ticks: usize,
    pub interval_ticks: usize,
}

#[derive(Clone, Copy)]
pub enum TimerFdError {
    BadTimerFd,
    NotReady,
}

static mut TIMERFDS: [TimerFdSlot; MAX_TIMERFDS] = [TimerFdSlot::EMPTY; MAX_TIMERFDS];

pub fn alloc() -> Option<TimerFd> {
    let ptr = unsafe { TIMERFDS.as_mut_ptr() };
    for idx in 0..MAX_TIMERFDS {
        let slot = unsafe { &mut *ptr.add(idx) };
        if !slot.used {
            *slot = TimerFdSlot {
                used: true,
                ..TimerFdSlot::EMPTY
            };
            return Some(TimerFd(idx));
        }
    }
    None
}

pub fn close(timerfd: TimerFd) {
    if let Some(slot) = slot_mut(timerfd) {
        *slot = TimerFdSlot::EMPTY;
    }
}

pub fn set(
    timerfd: TimerFd,
    deadline: Option<usize>,
    interval_ticks: usize,
) -> Result<(), TimerFdError> {
    let slot = slot_mut(timerfd).ok_or(TimerFdError::BadTimerFd)?;
    slot.pending = 0;
    slot.interval_ticks = interval_ticks;
    if let Some(deadline) = deadline {
        slot.next_deadline = deadline;
        slot.active = true;
    } else {
        slot.next_deadline = 0;
        slot.interval_ticks = 0;
        slot.active = false;
    }
    Ok(())
}

pub fn read(timerfd: TimerFd, now: usize) -> Result<u64, TimerFdError> {
    let slot = slot_mut(timerfd).ok_or(TimerFdError::BadTimerFd)?;
    refresh(slot, now);
    if slot.pending == 0 {
        return Err(TimerFdError::NotReady);
    }
    let expirations = slot.pending;
    slot.pending = 0;
    Ok(expirations)
}

pub fn state(timerfd: TimerFd, now: usize) -> Option<TimerFdState> {
    let slot = slot_mut(timerfd)?;
    refresh(slot, now);
    Some(state_from_slot(slot, now))
}

pub fn is_readable(timerfd: TimerFd, now: usize) -> bool {
    let Some(slot) = slot_mut(timerfd) else {
        return false;
    };
    refresh(slot, now);
    slot.pending > 0
}

pub fn ino(timerfd: TimerFd) -> u64 {
    5000 + timerfd.0 as u64
}

fn refresh(slot: &mut TimerFdSlot, now: usize) {
    if !slot.active || now < slot.next_deadline {
        return;
    }
    if slot.interval_ticks == 0 {
        slot.pending = slot.pending.saturating_add(1);
        slot.active = false;
        return;
    }

    let elapsed = now.saturating_sub(slot.next_deadline);
    let count = 1usize.saturating_add(elapsed / slot.interval_ticks);
    slot.pending = slot.pending.saturating_add(count as u64);
    let advance = slot.interval_ticks.saturating_mul(count);
    slot.next_deadline = slot.next_deadline.saturating_add(advance);
    if slot.next_deadline <= now {
        slot.next_deadline = now.saturating_add(slot.interval_ticks);
    }
}

fn state_from_slot(slot: &TimerFdSlot, now: usize) -> TimerFdState {
    TimerFdState {
        remaining_ticks: if slot.active {
            slot.next_deadline.saturating_sub(now)
        } else {
            0
        },
        interval_ticks: slot.interval_ticks,
    }
}

fn slot_mut(timerfd: TimerFd) -> Option<&'static mut TimerFdSlot> {
    if timerfd.0 >= MAX_TIMERFDS {
        return None;
    }
    let slot = unsafe { &mut TIMERFDS[timerfd.0] };
    slot.used.then_some(slot)
}
