pub const PIPE_BUF_SIZE: usize = 4096;

use crate::task::scheduler;

const MAX_PIPES: usize = 128;

#[derive(Clone, Copy)]
struct Pipe {
    buf: [u8; PIPE_BUF_SIZE],
    read_pos: usize,
    len: usize,
    readers: usize,
    writers: usize,
    used: bool,
}

impl Pipe {
    const EMPTY: Self = Self {
        buf: [0; PIPE_BUF_SIZE],
        read_pos: 0,
        len: 0,
        readers: 0,
        writers: 0,
        used: false,
    };
}

pub enum PipeReadResult {
    Data(usize),
    Empty,
    Eof,
    BadPipe,
}

pub enum PipeWriteResult {
    Written(usize),
    Full,
    Broken,
    BadPipe,
}

#[derive(Clone, Copy)]
pub struct PipeState {
    pub len: usize,
    pub readers: usize,
    pub writers: usize,
    pub capacity: usize,
}

static mut PIPES: [Pipe; MAX_PIPES] = [Pipe::EMPTY; MAX_PIPES];

pub fn alloc_pipe() -> Option<usize> {
    unsafe {
        let mut id = 0;
        while id < MAX_PIPES {
            if !PIPES[id].used {
                PIPES[id] = Pipe {
                    used: true,
                    ..Pipe::EMPTY
                };
                return Some(id);
            }
            id += 1;
        }
    }
    None
}

pub fn add_reader(id: usize) -> bool {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return false;
        };
        if !pipe.used {
            return false;
        }
        pipe.readers += 1;
        true
    }
}

pub fn add_writer(id: usize) -> bool {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return false;
        };
        if !pipe.used {
            return false;
        }
        pipe.writers += 1;
        true
    }
}

pub fn close_reader(id: usize) {
    unsafe {
        if let Some(pipe) = PIPES.get_mut(id)
            && pipe.used
            && pipe.readers > 0
        {
            pipe.readers -= 1;
            scheduler::wake_pipe_writers(id);
            release_if_empty(id);
        }
    }
}

pub fn close_writer(id: usize) {
    unsafe {
        if let Some(pipe) = PIPES.get_mut(id)
            && pipe.used
            && pipe.writers > 0
        {
            pipe.writers -= 1;
            scheduler::wake_pipe_readers(id);
            release_if_empty(id);
        }
    }
}

pub fn read(id: usize, out: &mut [u8]) -> PipeReadResult {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return PipeReadResult::BadPipe;
        };
        if !pipe.used {
            return PipeReadResult::BadPipe;
        }
        if pipe.len == 0 {
            return if pipe.writers == 0 {
                PipeReadResult::Eof
            } else {
                PipeReadResult::Empty
            };
        }
        let count = core::cmp::min(out.len(), pipe.len);
        for (idx, slot) in out.iter_mut().take(count).enumerate() {
            *slot = pipe.buf[(pipe.read_pos + idx) % PIPE_BUF_SIZE];
        }
        pipe.read_pos = (pipe.read_pos + count) % PIPE_BUF_SIZE;
        pipe.len -= count;
        scheduler::wake_pipe_writers(id);
        PipeReadResult::Data(count)
    }
}

pub fn peek(id: usize, offset: usize, out: &mut [u8]) -> PipeReadResult {
    unsafe {
        let Some(pipe) = PIPES.get(id) else {
            return PipeReadResult::BadPipe;
        };
        if !pipe.used {
            return PipeReadResult::BadPipe;
        }
        if offset >= pipe.len {
            return if pipe.writers == 0 {
                PipeReadResult::Eof
            } else {
                PipeReadResult::Empty
            };
        }
        let available = pipe.len - offset;
        let count = core::cmp::min(out.len(), available);
        for (idx, slot) in out.iter_mut().take(count).enumerate() {
            *slot = pipe.buf[(pipe.read_pos + offset + idx) % PIPE_BUF_SIZE];
        }
        PipeReadResult::Data(count)
    }
}

pub fn discard(id: usize, count: usize) -> PipeReadResult {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return PipeReadResult::BadPipe;
        };
        if !pipe.used {
            return PipeReadResult::BadPipe;
        }
        if pipe.len == 0 {
            return if pipe.writers == 0 {
                PipeReadResult::Eof
            } else {
                PipeReadResult::Empty
            };
        }
        let count = core::cmp::min(count, pipe.len);
        pipe.read_pos = (pipe.read_pos + count) % PIPE_BUF_SIZE;
        pipe.len -= count;
        scheduler::wake_pipe_writers(id);
        PipeReadResult::Data(count)
    }
}

pub fn write(id: usize, input: &[u8], require_atomic: bool) -> PipeWriteResult {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return PipeWriteResult::BadPipe;
        };
        if !pipe.used {
            return PipeWriteResult::BadPipe;
        }
        if pipe.readers == 0 {
            return PipeWriteResult::Broken;
        }
        let free = PIPE_BUF_SIZE - pipe.len;
        if free == 0 {
            return PipeWriteResult::Full;
        }
        if require_atomic && free < input.len() {
            return PipeWriteResult::Full;
        }
        let count = core::cmp::min(input.len(), free);
        let write_pos = (pipe.read_pos + pipe.len) % PIPE_BUF_SIZE;
        for (idx, byte) in input.iter().take(count).enumerate() {
            pipe.buf[(write_pos + idx) % PIPE_BUF_SIZE] = *byte;
        }
        pipe.len += count;
        scheduler::wake_pipe_readers(id);
        PipeWriteResult::Written(count)
    }
}

pub fn state(id: usize) -> Option<PipeState> {
    unsafe {
        let pipe = PIPES.get(id)?;
        pipe.used.then_some(PipeState {
            len: pipe.len,
            readers: pipe.readers,
            writers: pipe.writers,
            capacity: PIPE_BUF_SIZE,
        })
    }
}

fn release_if_empty(id: usize) {
    unsafe {
        let Some(pipe) = PIPES.get_mut(id) else {
            return;
        };
        if pipe.used && pipe.readers == 0 && pipe.writers == 0 {
            *pipe = Pipe::EMPTY;
        }
    }
}

pub fn smoke_check_atomic_small_write_requires_room() -> bool {
    let Some(id) = alloc_pipe() else {
        return false;
    };
    if !add_reader(id) || !add_writer(id) {
        close_reader(id);
        close_writer(id);
        return false;
    }

    let chunk = [0x41u8; 64];
    let mut remaining = PIPE_BUF_SIZE - 1;
    while remaining != 0 {
        let count = remaining.min(chunk.len());
        match write(id, &chunk[..count], true) {
            PipeWriteResult::Written(written) if written == count => {}
            _ => {
                close_reader(id);
                close_writer(id);
                return false;
            }
        }
        remaining -= count;
    }

    let rejected_small = matches!(write(id, &[0x42, 0x43], true), PipeWriteResult::Full);
    let unchanged = state(id).is_some_and(|state| state.len == PIPE_BUF_SIZE - 1);
    let partial_large = matches!(write(id, &[0x42, 0x43], false), PipeWriteResult::Written(1));
    let full_after_partial = state(id).is_some_and(|state| state.len == PIPE_BUF_SIZE);

    close_reader(id);
    close_writer(id);

    rejected_small && unchanged && partial_large && full_after_partial
}

