#[derive(Clone, Copy, PartialEq, Eq)]
pub struct Inotify(usize);

#[derive(Clone, Copy)]
struct Watch {
    used: bool,
    wd: i32,
    mask: u32,
    path: [u8; MAX_WATCH_PATH],
    path_len: usize,
    scratch_key: Option<ScratchWatchKey>,
}

impl Watch {
    const EMPTY: Self = Self {
        used: false,
        wd: 0,
        mask: 0,
        path: [0; MAX_WATCH_PATH],
        path_len: 0,
        scratch_key: None,
    };

    fn path(&self) -> &[u8] {
        &self.path[..self.path_len]
    }
}

#[derive(Clone, Copy)]
pub struct QueuedEvent {
    pub wd: i32,
    pub mask: u32,
    pub cookie: u32,
    pub name: [u8; MAX_EVENT_NAME],
    pub name_len: usize,
}

impl QueuedEvent {
    const EMPTY: Self = Self {
        wd: 0,
        mask: 0,
        cookie: 0,
        name: [0; MAX_EVENT_NAME],
        name_len: 0,
    };

    fn new(wd: i32, mask: u32, name: Option<&[u8]>) -> Self {
        let mut event = Self {
            wd,
            mask,
            cookie: 0,
            ..Self::EMPTY
        };
        if let Some(name) = name {
            let count = name.len().min(MAX_EVENT_NAME);
            event.name[..count].copy_from_slice(&name[..count]);
            event.name_len = count;
        }
        event
    }

    fn overflow() -> Self {
        Self {
            wd: -1,
            mask: IN_Q_OVERFLOW,
            cookie: 0,
            ..Self::EMPTY
        }
    }

    pub fn record_len(&self) -> usize {
        if self.name_len == 0 {
            0
        } else {
            align4(self.name_len + 1)
        }
    }

    pub fn size(&self) -> usize {
        EVENT_HEADER_SIZE + self.record_len()
    }
}

