        *entry = PTEntry::new_leaf(new_frame, {
            let f = entry.flags();
            PTEFlags::new(true, true, f.is_x(), true) // R+W, U=1, preserve X
        });
        entry.clear_cow();
    } else {
        // 唯一进程 → 原地恢复写权限
        entry.set_w(true);
        entry.clear_cow();
    }
    unsafe { asm!("sfence.vma") };
    true
}

