pub(crate) fn print_hex(mut val: usize) {
    for _ in 0..16 {
        let nibbel = ((val >> 60) & 0xF) as u8;
        let c = if nibbel < 10 {
            b'0' + nibbel
        } else {
            b'a' + nibbel - 10
        };
        console::putchar(c);
        val <<= 4;
    }
}

