const RESOLVE_NO_XDEV: usize = 0x01;
const RESOLVE_NO_MAGICLINKS: usize = 0x02;
const RESOLVE_NO_SYMLINKS: usize = 0x04;
const RESOLVE_BENEATH: usize = 0x08;
const RESOLVE_IN_ROOT: usize = 0x10;
const RESOLVE_CACHED: usize = 0x20;
const OPENAT2_STAGE1_SUPPORTED_RESOLVE: usize = RESOLVE_NO_MAGICLINKS | RESOLVE_NO_SYMLINKS;
const OPENAT2_UNSUPPORTED_RESOLVE: usize =
    RESOLVE_NO_XDEV | RESOLVE_BENEATH | RESOLVE_IN_ROOT | RESOLVE_CACHED;
const SYNC_FILE_RANGE_WAIT_BEFORE: usize = 1;
const SYNC_FILE_RANGE_WRITE: usize = 2;
const SYNC_FILE_RANGE_WAIT_AFTER: usize = 4;
const SYNC_FILE_RANGE_SUPPORTED_FLAGS: usize =
    SYNC_FILE_RANGE_WAIT_BEFORE | SYNC_FILE_RANGE_WRITE | SYNC_FILE_RANGE_WAIT_AFTER;

pub(super) fn sys_openat(dirfd: usize, path_ptr: *const u8, flags: usize, mode: usize) -> usize {
    let mut path_buf = [0u8; 128];
    let len = match copy_user_cstr(path_ptr as usize, &mut path_buf) {
        Ok(len) => len,
        Err(errno) => return errno,
    };
    let path = &path_buf[..len];

    if let Err(errno) = validate_open_path_flags(flags) {
        return errno;
    }

    let normalized = fs_path::normalize_stage1_path(dirfd, path).ok();
    if let Some(normalized) = normalized.as_ref()
        && let Some(result) = proc_fd::open_alias(normalized.as_bytes(), flags)
    {
        return result;
    }

    let kind = match open_path_kind(dirfd, path, flags) {
        Ok(kind) => kind,
        Err(errno) => {
            if flags & O_CREAT != 0 && errno == linux_error(ENOENT) {
                let kind = match fs_mutation::create_file_from_bytes(dirfd, path, mode) {
                    Ok(kind) => kind,
                    Err(errno) => return errno,
                };
                return open_existing_kind_with_optional_path(
                    kind,
                    flags,
                    normalized.as_ref().map(|path| path.as_bytes()),
                );
            }
            return errno;
        }
    };
    if flags & O_TMPFILE == O_TMPFILE {
        return open_tmpfile_kind(kind, flags, mode);
    }
    if flags & O_EXCL != 0 && flags & O_CREAT != 0 {
        return linux_error(EEXIST);
    }
    let access_result = fs_path::open_access_kind(kind, flags);
    if access_result != 0 {
        return access_result;
    }
    if flags & O_TRUNC != 0 {
        match kind {
            FdKind::ScratchFile(file) => {
                if let Err(error) = fs_mutation::truncate_scratch_file(file, 0) {
                    return scratch_error_to_errno(error);
                }
                if let Some(path) = scratchfs::file_path(file) {
                    inotify::notify_modify(path);
                }
            }
            kind if truncation_is_device_noop(kind) => {}
            _ => return linux_error(EROFS),
        }
    }
    open_existing_kind_with_optional_path(
        kind,
        flags,
        normalized.as_ref().map(|path| path.as_bytes()),
    )
}

fn truncation_is_device_noop(kind: FdKind) -> bool {
    matches!(
        kind,
        FdKind::Null | FdKind::Zero | FdKind::Tty | FdKind::Rtc | FdKind::Random | FdKind::Urandom
    )
}

fn open_path_kind(dirfd: usize, path: &[u8], flags: usize) -> Result<FdKind, usize> {
    let nofollow_final = flags & O_NOFOLLOW != 0 && !fs_path::has_trailing_slash(path);
    let final_link_policy = if nofollow_final {
        if flags & O_PATH != 0 {
            fs_path::FinalLinkPolicy::Keep
        } else {
            fs_path::FinalLinkPolicy::Reject
        }
    } else {
        fs_path::FinalLinkPolicy::Follow
    };
    let policy = fs_path::PathLookupPolicy {
        final_symlink: final_link_policy,
        final_magic: final_link_policy,
    };
    fs_path::resolve_stage1_path_with_policy(dirfd, path, flags, policy)
}

struct OpenHow {
    flags: usize,
    mode: usize,
    resolve: usize,
}

pub(super) fn sys_openat2(dirfd: usize, path_ptr: *const u8, how: *const u8, size: usize) -> usize {
    let how = match read_open_how(how, size) {
        Ok(how) => how,
        Err(errno) => return errno,
    };
    if how.flags & !OPENAT2_SUPPORTED_FLAGS != 0 {
        return linux_error(EINVAL);
    }
    if let Err(errno) = validate_openat2_resolve(dirfd, path_ptr, how.resolve) {
        return errno;
    }
    if how.mode != 0 && how.flags & (O_CREAT | O_TMPFILE) == 0 {
        return linux_error(EINVAL);
    }
    sys_openat(dirfd, path_ptr, how.flags, how.mode)
}

fn validate_openat2_resolve(
    dirfd: usize,
    path_ptr: *const u8,
    resolve: usize,
) -> Result<(), usize> {
    if resolve == 0 {
        return Ok(());
    }
    if resolve & !(OPENAT2_STAGE1_SUPPORTED_RESOLVE | OPENAT2_UNSUPPORTED_RESOLVE) != 0 {
        return Err(linux_error(EINVAL));
    }
    if resolve & OPENAT2_UNSUPPORTED_RESOLVE != 0 {
        return Err(linux_error(ENOSYS));
    }
    // Use lexical normalization here so RESOLVE_NO_SYMLINKS can still reject
    // an intermediate link before normal open follows it.
    let mut path_buf = [0u8; 128];
    let len = copy_user_cstr(path_ptr as usize, &mut path_buf)?;
    let normalized = fs_path::normalize_stage1_path_lexical(dirfd, &path_buf[..len])?;
    let mut target = [0u8; rootfs::ROOTFS_MAX_PATH];
    if (resolve & (RESOLVE_NO_MAGICLINKS | RESOLVE_NO_SYMLINKS) != 0)
        && (proc_fd::is_alias(normalized.as_bytes())
            || procfs::pid_link_info(normalized.as_bytes(), &mut target).is_some())
    {
        return Err(linux_error(ELOOP));
    }
    if resolve & RESOLVE_NO_SYMLINKS != 0
        && fs_path::normalized_path_has_stage1_symlink_component(normalized.as_bytes())
    {
        return Err(linux_error(ELOOP));
    }
    Ok(())
}

fn validate_open_path_flags(flags: usize) -> Result<(), usize> {
    if flags & O_PATH == 0 {
        return Ok(());
    }
    let has_tmpfile = flags & O_TMPFILE == O_TMPFILE;
    if flags & (O_ACCMODE | O_CREAT | O_EXCL | O_TRUNC) != 0 || has_tmpfile {
        return Err(linux_error(EINVAL));
    }
    Ok(())
}

fn read_open_how(ptr: *const u8, size: usize) -> Result<OpenHow, usize> {
    if ptr.is_null() {
        return Err(linux_error(EFAULT));
    }
    if size < OPEN_HOW_SIZE {
        return Err(linux_error(EINVAL));
    }
    ensure_user_range(ptr as usize, size, false)?;
    let flags = read_user_u64(ptr as usize)?;
    let mode = read_user_u64(ptr as usize + 8)?;
    let resolve = read_user_u64(ptr as usize + 16)?;
    if size > OPEN_HOW_SIZE {
        validate_open_how_tail(unsafe { ptr.add(OPEN_HOW_SIZE) }, size - OPEN_HOW_SIZE)?;
    }
    Ok(OpenHow {
        flags: usize::try_from(flags).map_err(|_| linux_error(EINVAL))?,
        mode: usize::try_from(mode).map_err(|_| linux_error(EINVAL))?,
        resolve: usize::try_from(resolve).map_err(|_| linux_error(EINVAL))?,
    })
}

