pub fn has_other_ready() -> bool {
    let cur = unsafe { CURRENT };
    let ptr = unsafe { PROCESS_LIST.as_ptr() };
    for i in 1..MAX_PROCESSES {
        let idx = (cur + i) % MAX_PROCESSES;
        unsafe {
            let slot = &*ptr.add(idx);
            if let Some(proc) = slot.as_ref()
                && matches!(proc.state, ProcessState::Ready)
            {
                return true;
            }
        }
    }
    false
}

pub(crate) fn timer_should_preempt_current(woke_future_event: bool) -> bool {
    if !matches!(current().state, ProcessState::Running) {
        return false;
    }
    if woke_future_event && !has_other_ready() {
        return true;
    }
    let cur = current();
    let cur_idx = unsafe { CURRENT };
    let ptr = unsafe { PROCESS_LIST.as_ptr() };
    for i in 1..MAX_PROCESSES {
        let idx = (cur_idx + i) % MAX_PROCESSES;
        unsafe {
            let slot = &*ptr.add(idx);
            if let Some(proc) = slot.as_ref()
                && matches!(proc.state, ProcessState::Ready)
                && ready_candidate_should_preempt(proc, cur)
            {
                return true;
            }
        }
    }
    false
}

