    const READY_IDX: usize = MAX_PROCESSES - 10;

    let no_event_no_peer = !timer_should_preempt_current(false);
    let event_preempts = timer_should_preempt_current(true);

    let mut peer = Process::STAGING;
    peer.pid = 0x5c4ed;
    peer.thread_group_id = peer.pid;
    peer.state = ProcessState::Ready;
    unsafe {
        PROCESS_LIST[READY_IDX].set_occupied(peer);
    }
    let ready_peer_preempts = timer_should_preempt_current(false);
    unsafe {
        PROCESS_LIST[READY_IDX] = ProcessSlot::EMPTY;
    }

    no_event_no_peer && event_preempts && ready_peer_preempts
}

pub fn smoke_check_priority_scheduler_ordering() -> bool {
    const NORMAL_IDX: usize = MAX_PROCESSES - 12;
    const RT_LOW_IDX: usize = MAX_PROCESSES - 11;
    const RT_HIGH_IDX: usize = MAX_PROCESSES - 10;

    let cur = unsafe { CURRENT };
    let mut normal = Process::STAGING;
    normal.pid = 0x51001;
    normal.thread_group_id = normal.pid;
    normal.state = ProcessState::Ready;

    let mut rt_low = Process::STAGING;
    rt_low.pid = 0x51002;
    rt_low.thread_group_id = rt_low.pid;
    rt_low.state = ProcessState::Ready;
    rt_low.sched_policy = SCHED_FIFO_POLICY;
    rt_low.sched_priority = 10;

    let mut rt_high = Process::STAGING;
    rt_high.pid = 0x51003;
    rt_high.thread_group_id = rt_high.pid;
    rt_high.state = ProcessState::Ready;
    rt_high.sched_policy = SCHED_FIFO_POLICY;
    rt_high.sched_priority = 80;

    unsafe {
        PROCESS_LIST[NORMAL_IDX].set_occupied(normal);
        PROCESS_LIST[RT_LOW_IDX].set_occupied(rt_low);
        PROCESS_LIST[RT_HIGH_IDX].set_occupied(rt_high);
    }
    let picked_high = pick_ready_after(cur) == Some(RT_HIGH_IDX);
    unsafe {
        PROCESS_LIST[RT_HIGH_IDX] = ProcessSlot::EMPTY;
    }
    let picked_low = pick_ready_after(cur) == Some(RT_LOW_IDX);
    unsafe {
        PROCESS_LIST[NORMAL_IDX] = ProcessSlot::EMPTY;
        PROCESS_LIST[RT_LOW_IDX] = ProcessSlot::EMPTY;
    }

    picked_high && picked_low
}

// ── 选下一个 Ready 进程 ──

fn pick_next() -> usize {
    let cur = unsafe { CURRENT };
    wake_future_events(crate::timer::read_time());
    if let Some(idx) = pick_ready_after(cur) {
        return idx;
    }
    while has_future_wakeup() {
        if wake_future_events(crate::timer::read_time()) {
            crate::syscall::rearm_timer();
        }
        if let Some(idx) = pick_ready_after(cur) {
            return idx;
        }
        idle_wait_for_future_wakeup();
    }
    MAX_PROCESSES // sentinel: 无可运行进程
}

fn idle_wait_for_future_wakeup() {
    crate::syscall::rearm_timer();
    // WFI wakes for locally enabled timer interrupts even while global SIE is
    // clear. Keep SIE clear here: trap_entry treats S-mode nested traps as fatal.
    unsafe {
        asm!("wfi");
    }
}

pub fn complete_blocked_syscall(proc: &mut Process, result: usize) {
    proc.trap_frame.set_a0(result);
    proc.trap_frame.sepc += 4;
}

pub fn replace_completed_blocked_syscall_result(proc: &mut Process, result: usize) {
    proc.trap_frame.set_a0(result);
}

// ── 调度核心 ──

/// 保存当前进程 → 选新进程 → 恢复新进程 → 跳转 trap_exit_restore
/// 不返回。
pub fn schedule() -> ! {
    let _ = take_reschedule_request();

    // 1. 保存当前进程上下文
    let cur = current();
    // trap frame 固定在 kernel_sp - TrapFrame::SIZE（由 trap_entry 写入），
    // 不能用当前 sp，因为 schedule() 调用链中 sp 早已离开该位置。
    let frame_base = cur.kernel_trap_frame_base();
    unsafe {
        TrapFrame::copy_from_stack(frame_base, &mut cur.trap_frame);
    }

    // 2. 选新进程。信号投递可能在真正恢复用户态前把候选任务停住，
    // 这种任务不能被写回并执行，继续挑下一个 Ready 任务。
    loop {
        let next_idx = pick_next();
        if next_idx == MAX_PROCESSES {
            crate::sbi::shutdown();
        }

        unsafe { CURRENT = next_idx };
        current().state = ProcessState::Running;
        let mut signal_frame = current().trap_frame;
        crate::syscall::signal::prepare_signal_return(&mut signal_frame);
        current().trap_frame = signal_frame;
        if !matches!(current().state, ProcessState::Stopped) {
            break;
        }
    }

    // 3. 切换硬件状态
    let next = current();

    // 提前读出所有需要的值（mv sp 之后不能再访问 Rust 局部变量）
    let next_satp = next.address_space.page_table.satp_val();
    let next_kernel_sp = next.kernel_sp;
    let new_sp = next.kernel_trap_frame_base();
    unsafe {
        next.trap_frame.write_to_stack(new_sp);
    }

    // 切页表、写 trap frame、切换 sscratch/sp/sstatus、跳转 ——
    // 全部放在一个 asm 块里。mv sp 之后编译器不能再插入任何指令。
    unsafe {
        asm!(
            "csrw satp, {next_satp}",
            "sfence.vma",
            "addi sp, {next_kernel_sp}, -288",
            "la   t0, trap_exit_restore",
            "jr   t0",
            next_satp = in(reg) next_satp,
            next_kernel_sp = in(reg) next_kernel_sp,
            options(noreturn),
        );
    }
}

